import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const Register = () => {
  const [username, setUsername] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const navigate = useNavigate();

  const handleRegister = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5000/api/auth/register", { username, email, password });
      alert("Registration successful! Please login.");
      navigate("/login");
    } catch (err) {
      alert("Error registering user.");
    }
  };

  return (
    <div className="flex justify-center items-center h-[80vh] bg-gray-100">
      <form onSubmit={handleRegister} className="bg-white p-8 rounded shadow-md w-80">
        <h2 className="text-2xl font-bold mb-4 text-center">Create Account</h2>
        <input className="w-full mb-3 p-2 border rounded" type="text" placeholder="Username" onChange={e=>setUsername(e.target.value)} />
        <input className="w-full mb-3 p-2 border rounded" type="email" placeholder="Email" onChange={e=>setEmail(e.target.value)} />
        <input className="w-full mb-4 p-2 border rounded" type="password" placeholder="Password" onChange={e=>setPassword(e.target.value)} />
        <button className="w-full bg-blue-500 text-white py-2 rounded font-bold hover:bg-blue-600">Register</button>
      </form>
    </div>
  );
};

export default Register;
